/**
 * @param {unknown[]} inputs
 * @returns {boolean} to break out current process
 * @returns {{type: EntryType; value: unknown}[]}
 *
 * @example
 * const x = inputs[0];
 * const y = inputs[1];
 * return [{type: "number", value: x + y}];
 */
const patreon = inputs[0]
const type = inputs[1];
const filters = {
  'acid': patreon ? {} : {"hue": -100},
  'bleed': patreon ? {} : {"hue": 145},
  'mental': patreon ? {} : {"saturate": 0.8, "hue": 20}, 
  'poison': patreon ? {} : {"hue": 180},
  'sonic': {"hue": -50},  
  'spirit': patreon ? {} : {"hue": 155}, 
  'void': patreon ? {} : {"hue": -165},
}

return [{type: "text", value: JSON.stringify(filters?.[type] || {})}];

/**
 * @param {unknown[]} inputs
 * @returns {boolean} to break out current process
 * @returns {{type: EntryType; value: unknown}[]}
 *
 * @example
 * const x = inputs[0];
 * const y = inputs[1];
 * return [{type: "number", value: x + y}];
 */
const patreon = inputs[0]
const type = inputs[1];
const files = { 
  'fire': {fadeIn: 500, fadeOut: 250, duration: 2400  },  
  'poison': {fadeIn: 500, fadeOut: 250, duration: 2400,  "opacity": 0.8}, 
   'spirit': {fadeIn: 500, fadeOut: 250, duration: 2400  }
}

console.log([
  {type: "number", value: files[type]?.fadeIn || 0},
  {type: "number", value: files[type]?.fadeOut || 0},
  {type: "number", value: files[type]?.duration || 0},
  {type: "number", value: files[type]?.opacity || 1},
])

return [
  {type: "number", value: files[type]?.fadeIn || 0},
  {type: "number", value: files[type]?.fadeOut || 0},
  {type: "number", value: files[type]?.duration || 0},
  {type: "number", value: files[type]?.opacity || 1},
];
